  stimulus_type = NULL,
  options = '[{"id":"A","text":"\"The most recent scientific research on the impact of climate change on coral reefs indicates that rising sea levels are leading to the destruction of reefs, in many locations the damage is severe.\"","is_correct":false,"explanation":"This choice does not follow from the information given or contains a calculation error. Choice A is incorrect because it either misreads the passage, overgeneralizes a limited detail, or focuses on information irrelevant to the question stem. Compare this option against the grammar or logic rule tested by the stem before selecting a final answer."},{"id":"B","text":"\"The most recent scientific research on the impact of climate change on coral reefs indicates that rising sea levels are leading to the destruction of reefs; in many locations the damage is severe.\"","is_correct":false,"explanation":"This choice does not follow from the information given or contains a calculation error. Choice B is incorrect because it either misreads the passage, overgeneralizes a limited detail, or focuses on information irrelevant to the question stem. Compare this option against the grammar or logic rule tested by the stem before selecting a final answer."},{"id":"C","text":"\"The most recent scientific research on the impact of climate change on coral reefs indicates that rising sea levels are leading to the destruction of reefs, in many locations, the damage is severe.\"","is_correct":true,"explanation":"The comma after \"reefs\" is correct because it separates two independent clauses: the first clause is \"The most recent scientific research on the impact of climate change on coral reefs indicates that rising sea levels are leading to the destruction of reefs\" and the second is \"in many locations, the. Choice C matches the question''s requirement and is consistent with the passage''s central claim or supporting detail. Compare this option against the grammar or logic rule tested by the stem before selecting a final answer."},{"id":"D","text":"\"The most recent scientific research on the impact of climate change on coral reefs indicates that rising sea levels are leading to the destruction of reefs—in many locations, the damage is severe.\"","is_correct":false,"explanation":"This choice does not follow from the information given or contains a calculation error. Choice D is incorrect because it either misreads the passage, overgeneralizes a limited detail, or focuses on information irrelevant to the question stem. Compare this option against the grammar or logic rule tested by the stem before selecting a final answer."}]'::jsonb,
